this is my final work-around.

```python
class PrimitiveValueSchema:
    schema_class = None
    key = "value"
    missing = None

    def __init__(self, *args, **kwargs):
        self.schema = self.schema_class(*args, **kwargs)

    def load(self, value):  # don't support many
        data = {self.key: value}
        return self.schema.load(data)

    def dump(self, value):  # don't support many
        data = {self.key: value}
        r, errors = self.schema.dump(data, update_fields=False)
        return MarshalResult(
            data=r.get(self.key) or self.missing,
            errors=errors.get(self.key) or errors,
        )


class IntSchema(PrimitiveValueSchema):
    class schema_class(Schema):
        value = fields.Integer(required=True)


class IntListSchema(PrimitiveValueSchema):
    key = "values"

    class schema_class(Schema):
        values = fields.List(fields.Integer(), required=True)
```

For CRUD updating, use the [partial loading](https://marshmallow.readthedocs.io/en/latest/quickstart.html#partial-loading),

```python
from marshmallow_jsonapi import Schema, fields

class Post:
    def __init__(self, id, title, body):
        self.id = id
        self.title = title
        self.body = body

    def __repr__(self):
        return '<Post(title={self.title!r} body={self.body!r})>'.format(self=self)

post = Post(id='1', title='Title', body='Original Body')

class PostSchema(Schema):
    id = fields.Str(dump_only=True)
    title = fields.Str(required=True)
    body = fields.Str()

    class Meta:
        type_ = 'posts'
        strict = True

post_schema = PostSchema()

input_data = {
    'data': {
        'type': 'posts',
        'attributes': {
            'body': 'New Body',
        }
    }
}

serialized = post_schema.load(input_data, partial=True)
for key, value in serialized.items():
    setattr(post, key, value)

print(post)
# <Post(title='Title' body='New Body')>
```

